patch:
--- a/shifter.v
+++ b/shifter.v
@@ -9,8 +9,8 @@ module shifter_wrapper (
 );
   shifter_32bit shift_inst (
-    .data_in(data),
+    .din(data),
-    .shamt(shift_amount),
+    .shamt(shift_amount[4:0]),
     .shifted_data(result)
   );
 endmodule

before_code:
module shifter_32bit (
  input [31:0] din,
  input [4:0] shamt,
  output [31:0] shifted_data
);
  assign shifted_data = din >> shamt;
endmodule

module shifter_wrapper (
  input [31:0] data,
  input [7:0] shift_amount,
  output [31:0] result
);
  shifter_32bit shift_inst (
    .data_in(data),
    .shamt(shift_amount),
    .shifted_data(result)
  );
endmodule

after_code:
module shifter_32bit (
  input [31:0] din,
  input [4:0] shamt,
  output [31:0] shifted_data
);
  assign shifted_data = din >> shamt;
endmodule

module shifter_wrapper (
  input [31:0] data,
  input [7:0] shift_amount,
  output [31:0] result
);
  shifter_32bit shift_inst (
    .din(data),
    .shamt(shift_amount[4:0]),
    .shifted_data(result)
  );
endmodule
